  "description": "One concrete optimization target emitted by an analyzer.\n\nConsensus-routing fields (`breakage_class`, `poc_implementable`,\n`poc_test_scope`, `consensus_writeup`) are conditionally required based\non `consensus_breaking` + `breakage_class`; see\n[`AnalyzerTarget::validate_model`] for the cross-field rules.",
  "properties": {
    "breakage_class": {
      "anyOf": [
        {
          "$ref": "#/$defs/BreakageClass"
        },
        {
          "type": "null"
        }
      ],
      "description": "Required when `consensus_breaking == true`. Forbidden otherwise."
    },
    "bucket": {
      "$ref": "#/$defs/Bucket",
      "description": "Authoritative bucket classification."
    },
    "consensus_breaking": {
      "description": "True iff implementing this fix would change consensus rules.",
      "type": "boolean"
    },
    "consensus_writeup": {
      "description": "Required when `consensus_breaking == true`. Forbidden otherwise.",
      "type": [
        "string",
        "null"
      ]
    },
    "evidence": {
      "description": "Trace + code evidence.",
      "type": "string"
    },
    "evidence_queries": {
      "description": "Structured DB evidence the analyzer used to identify this target.\nRequired on non-consensus targets; consensus targets may omit it\nbecause they do not reach the benchmark/result-analysis phases.",
      "items": {
        "$ref": "#/$defs/EvidenceQuery"
      },
      "type": "array"
    },
    "expected_improvement": {
      "$ref": "#/$defs/ImprovementVector",
      "description": "Three-axis honest improvement estimate."
    },
    "files": {
      "description": "Repo-relative paths, ordered most-likely first.",
      "items": {
        "type": "string"
      },
      "type": "array"
    },
    "fix_signature": {
      "description": "Stable kebab-case structural-fix identifier.",
      "pattern": "^[a-z0-9][a-z0-9-]*$",
      "type": "string"
    },
    "hotspot": {
      "$ref": "#/$defs/Hotspot",
      "description": "Hotspot record (self/total wall, calls, location)."
    },
    "poc_implementable": {
      "description": "Required when `consensus_breaking == true`. Forbidden otherwise.\nForced to `false` when `breakage_class == BlockValidation`.",
      "type": [
        "boolean",
        "null"
      ]
    },
    "poc_test_scope": {
      "description": "Required when `poc_implementable == true`. Forbidden otherwise.",
      "items": {
        "type": "string"
      },
      "type": [
        "array",
        "null"
      ]
    },
    "proposed_change": {
      "description": "Concrete proposed change.",
      "type": "string"
    },
    "risk": {
      "$ref": "#/$defs/Risk",
      "description": "Subjective risk level."
    },
    "target_span": {
      "description": "Span the optimizer should target. Must NOT be a bucket anchor or a\nnon-target entry.",
      "type": "string"
    },
    "verification_plan": {
      "description": "Verification plan (which tests must pass / what to spot-check).",
      "type": "string"
    },
    "verification_replay": {
      "anyOf": [
        {
          "$ref": "#/$defs/VerificationReplay"
        },
        {
          "type": "null"
        }
      ],
      "description": "Targeted-replay recipe. Required on non-consensus\n(`consensus_breaking == false`) targets — Phase 1.8 + Phase 3\nrun every invocation in\n`verification_replay.invocations[]` and the post-bench\nresults-analyzer (Phase 3.5) pairs them by id. Optional and\nignored on consensus targets (which don't reach the bench).\nSee [`VerificationReplay`] for the invocation contract."
    }
  },
