impl<T: MarfTrieId> MarfConnection<T> for ReopenedTrieStorageConnection<'_, T> {
    fn with_conn<F, R>(&mut self, exec: F) -> R
    where
        F: FnOnce(&mut TrieStorageConnection<T>) -> R,
    {
        let mut conn = self.connection();
        exec(&mut conn)
    }

    fn sqlite_conn(&self) -> &Connection {
        self.db_conn()
    }
}

impl<T: MarfTrieId> MarfConnection<T> for MARF<T> {
    fn with_conn<F, R>(&mut self, exec: F) -> R
    where
        F: FnOnce(&mut TrieStorageConnection<T>) -> R,
    {
        let mut conn = self.storage.connection();
        exec(&mut conn)
    }
    fn sqlite_conn(&self) -> &Connection {
        self.storage.sqlite_conn()
    }
}

///
/// MarfTransaction represents a connection to a MARF index,
///   with an open storage transaction. If this struct is
///   dropped without calling commit(), the storage transaction is
///   aborted
///
impl<'a, T: MarfTrieId> MarfTransaction<'a, T> {
    #[cfg_attr(feature = "profiler", stacks_profiler::profile)]
    pub fn commit(mut self) -> Result<(), Error> {
        if self.storage.readonly() {
            return Err(Error::ReadOnlyError);
        }
        if let Some(_tip) = self.open_chain_tip.take() {
            self.storage.flush()?;
        }
        self.storage.commit_tx();
        Ok(())
    }

    /// Finish writing the next trie in the MARF, but change the hash of the current Trie's
    /// block hash to something other than what we opened it as.  This persists all changes.
    #[cfg_attr(feature = "profiler", stacks_profiler::profile)]
    pub fn commit_to(mut self, real_bhh: &T) -> Result<(), Error> {
        if self.storage.readonly() {
            return Err(Error::ReadOnlyError);
        }
        if self.storage.unconfirmed() {
            return Err(Error::UnconfirmedError);
        }
        if let Some(_tip) = self.open_chain_tip.take() {
            self.storage.flush_to(real_bhh)?;
            self.storage.commit_tx();
        }
        Ok(())
    }

    /// Finish writing the next trie in the MARF -- this is used by miners
    ///   to commit the mined block, but write it to the mined_block table,
    ///   rather than out to the marf_data table (this prevents the
    ///   miner's block from getting stepped on after the sortition).
    #[cfg_attr(feature = "profiler", stacks_profiler::profile)]
    pub fn commit_mined(mut self, bhh: &T) -> Result<(), Error> {
        if self.storage.readonly() {
            return Err(Error::ReadOnlyError);
        }
        if self.storage.unconfirmed() {
            return Err(Error::UnconfirmedError);
        }
        if let Some(_tip) = self.open_chain_tip.take() {
            self.storage.flush_mined(bhh)?;
            self.storage.commit_tx();
        }
        Ok(())

    .map_err(|e| e.into())
}

#[cfg_attr(
    feature = "profiler",
    stacks_profiler::profile(sample_rate = 8, unsampled = "count_only")
)]
pub fn get_confirmed_block_identifier<T: MarfTrieId>(
    conn: &Connection,
    bhh: &T,
) -> Result<Option<u32>, Error> {
    conn.query_row(
        "SELECT block_id FROM marf_data WHERE block_hash = ? AND unconfirmed = 0",
        &[bhh],
        |row| row.get("block_id"),
    )
    .optional()
    .map_err(|e| e.into())
}

#[cfg_attr(
    feature = "profiler",
    stacks_profiler::profile(sample_rate = 8, unsampled = "count_only")
)]
pub fn get_unconfirmed_block_identifier<T: MarfTrieId>(
    conn: &Connection,
    bhh: &T,
) -> Result<Option<u32>, Error> {
    conn.query_row(
        "SELECT block_id FROM marf_data WHERE block_hash = ? AND unconfirmed = 1",
        &[bhh],
        |row| row.get("block_id"),
    )
    .optional()
    .map_err(|e| e.into())
}

#[cfg_attr(feature = "profiler", stacks_profiler::profile(sample_rate = 8))]
pub fn get_block_hash<T: MarfTrieId>(conn: &Connection, local_id: u32) -> Result<T, Error> {
    let result = conn
        .query_row(
            "SELECT block_hash FROM marf_data WHERE block_id = ?",
            params![local_id],
            |row| row.get("block_hash"),
        )
        .optional()?;
    result.ok_or_else(|| {
        error!("Failed to get block header hash of local ID {}", local_id);
        Error::NotFoundError
    })
}

/// Write a serialized trie to sqlite
#[cfg_attr(feature = "profiler", stacks_profiler::profile)]
pub fn write_trie_blob<T: MarfTrieId>(
    conn: &Connection,
    block_hash: &T,
    data: &[u8],
) -> Result<u32, Error> {
    let args = params![block_hash, data, 0, 0, 0,];
    let mut s =
        conn.prepare("INSERT INTO marf_data (block_hash, data, unconfirmed, external_offset, external_length) VALUES (?, ?, ?, ?, ?)")?;
    let block_id = s
        .insert(args)?
        .try_into()
        .expect("EXHAUSTION: MARF cannot track more than 2**31 - 1 blocks");

/// Add a new value to the Trie at the location pointed at by the cursor.
/// Returns a ptr to be inserted into the last node visited by the cursor.
pub fn add_value<T: MarfTrieId>(
    storage: &mut TrieStorageConnection<T>,
    cursor: &mut TrieCursor<T>,
    value: &mut TrieLeaf,
) -> Result<TriePtr, Error> {
    let mut node = match cursor.node() {
        Some(n) => n,
        None => panic!("Cursor is uninitialized"),
    };

    if cursor.eop() {
        match node {
            TrieNodeType::Leaf(_) => Trie::replace_leaf(storage, cursor, value),
            _ => Trie::insert_leaf(storage, cursor, value, &mut node),
        }
    } else {
        // didn't reach the end of the path, so we're on an intermediate node
        // or we're somewhere in the path of a leaf.
        // Either tack the leaf on (possibly promoting the node), or splice the leaf in.
        if cursor.eonp(&node) {
            trace!(
                "eop = {}, eonp = {}, c = {cursor:?}, node = {node:?}",
                cursor.eop(),
                cursor.eonp(&node),
            );
            Trie::insert_leaf(storage, cursor, value, &mut node)
        } else {
            match node {
                TrieNodeType::Leaf(ref mut data) => {
                    Trie::promote_leaf_to_node4(storage, cursor, data, value)
                }
                _ => Trie::splice_leaf(storage, cursor, value, &mut node),
            }
        }
    }
}

